<div class="card"><div class="card-header d-flex justify-content-between align-items-center"><span>Tabla: Cajas POS</span><a class="<?= e(\Aplicacion\Servicios\ExcelExpoFormato::BOTON_CLASES) ?>" style="<?= e(\Aplicacion\Servicios\ExcelExpoFormato::BOTON_ESTILO) ?>" href="<?= e(url('/app/punto-venta/cajas/exportar/excel')) ?>"><?= e(\Aplicacion\Servicios\ExcelExpoFormato::BOTON_TEXTO) ?></a></div><div class="card-body"><table class="table table-sm"><thead><tr><th>ID</th><th>Nombre</th><th>Código</th><th>Estado</th><th class="text-end">Acciones</th></tr></thead><tbody><?php foreach($cajas as $caja): ?><tr><td><?= (int)$caja['id'] ?></td><td><?= e($caja['nombre']) ?></td><td><?= e($caja['codigo']) ?></td><td><?= e($caja['estado']) ?></td><td class="text-end"><div class="dropdown"><button class="btn btn-light btn-sm dropdown-toggle" data-bs-toggle="dropdown">Acciones</button><ul class="dropdown-menu dropdown-menu-end"><li><a class="dropdown-item" href="<?= e(url('/app/punto-venta/cajas/ver/' . (int) $caja['id'])) ?>">Ver</a></li><li><a class="dropdown-item" href="<?= e(url('/app/punto-venta/cajas/editar/' . (int) $caja['id'])) ?>">Editar</a></li><li><form method="POST" action="<?= e(url('/app/punto-venta/cajas/eliminar/' . (int) $caja['id'])) ?>" onsubmit="return confirm('¿Inactivar esta caja?')"><?= csrf_campo() ?><button class="dropdown-item text-danger">Eliminar</button></form></li></ul></div></td></tr><?php endforeach; ?></tbody></table></div></div>
